-- ================================================================
-- Migracion 003: Poblar socios_profesores con centro (Excel 31-mar-2026)
-- Ejecutar en Supabase > SQL Editor > New query > Run
-- ================================================================


-- Total: 112 registros (85 con centro, 27 sin centro)
-- Verificar:
SELECT COUNT(*) AS total FROM socios_profesores;
SELECT COUNT(*) AS con_centro FROM socios_profesores WHERE centro IS NOT NULL;
SELECT s.num_socio, s.apellidos, sp.centro FROM socios s JOIN socios_profesores sp ON s.id = sp.socio_id ORDER BY s.num_socio LIMIT 20;